import 'package:firebase_auth/firebase_auth.dart'; import 'package:injectable/injectable.dart'; import '../utils/app_logger.dart'; @singleton class SessionManager { bool _isActive = false; String? _currentSessionId; bool get isActive => _isActive; String? get currentSessionId => _currentSessionId; String? get userId => FirebaseAuth.instance.currentUser?.uid; void startSession(String sessionId) { _isActive = true; _currentSessionId = sessionId; AppLogger.info('Session started: $sessionId'); } void endSession() { _isActive = false; _currentSessionId = null; AppLogger.info('Session ended'); } }